const rawText = $input.first().json.data;

if (!rawText) {
  throw new Error('No text content found');
}

const lines = rawText.split(/\r?\n/);
const chunks = [];
let currentChunkLines = [];
let currentSubSection = '';

const sectionNames = {
  '1': 'Registration and Credit Hour Limits',
  '2': 'Prerequisites and Course Offerings',
  '3': 'Grading and Attendance',
  '4': 'Graduation Requirements',
  '5': 'Scheduling and Delivery Policies'
};

for (const line of lines) {
  const trimmed = line.trim();
  if (!trimmed) continue;

  const secMatch = trimmed.match(/^SECTION\s+(\d+):\s*(.+)/i);
  if (secMatch) {
    if (currentSubSection && currentChunkLines.length > 0) {
      const secNum = currentSubSection.split('.')[0];
      chunks.push({
        json: {
          text: currentChunkLines.join(' '),
          chunk_id: 'chunk_' + currentSubSection.replace('.', '_'),
          section: sectionNames[secNum] || 'Section ' + secNum,
          sub_section: currentSubSection
        }
      });
    }
    currentChunkLines = [];
    currentSubSection = '';
    continue;
  }

  const subMatch = trimmed.match(/^(\d+\.\d+)\s+(.+)/);
  if (subMatch) {
    if (currentSubSection && currentChunkLines.length > 0) {
      const secNum = currentSubSection.split('.')[0];
      chunks.push({
        json: {
          text: currentChunkLines.join(' '),
          chunk_id: 'chunk_' + currentSubSection.replace('.', '_'),
          section: sectionNames[secNum] || 'Section ' + secNum,
          sub_section: currentSubSection
        }
      });
    }
    currentSubSection = subMatch[1];
    currentChunkLines = [trimmed];
  } else {
    currentChunkLines.push(trimmed);
  }
}

if (currentSubSection && currentChunkLines.length > 0) {
  const secNum = currentSubSection.split('.')[0];
  chunks.push({
    json: {
      text: currentChunkLines.join(' '),
      chunk_id: 'chunk_' + currentSubSection.replace('.', '_'),
      section: sectionNames[secNum] || 'Section ' + secNum,
      sub_section: currentSubSection
    }
  });
}

return chunks;

